CustomField.formula:
IF(
    ISPICKVAL(Regime_Contratacao__c, "PJ"),
    20,
    IF(Faltas_Injustificadas__c <= 5, 30,
        IF(Faltas_Injustificadas__c <= 14, 24,
            IF(Faltas_Injustificadas__c <= 23, 18,
                IF(Faltas_Injustificadas__c <= 32, 12, 0)
            )
        )
    )
)
